func (h *Handler) PasswordLogin(w http.ResponseWriter, r *http.Request) {
	var req PasswordLoginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeError(w, http.StatusBadRequest, "invalid request body")
		return
	}

	email := normalizeEmail(req.Email)
	if email == "" || req.Password == "" {
		writeError(w, http.StatusBadRequest, "email and password are required")
		return
	}

	superAdminEmail, superAdminPassword := configuredSuperAdminCredentials()
	if superAdminEmail == "" || superAdminPassword == "" {
		writeError(w, http.StatusServiceUnavailable, "super admin login is not configured")
		return
	}

	if subtle.ConstantTimeCompare([]byte(email), []byte(superAdminEmail)) != 1 ||
		subtle.ConstantTimeCompare([]byte(req.Password), []byte(superAdminPassword)) != 1 {
		writeError(w, http.StatusBadRequest, "invalid email or password")
		return
	}

	user, err := h.findOrCreateUser(r.Context(), email)
	if err != nil {
		writeError(w, http.StatusInternalServerError, "failed to create user")
		return
	}

	if err := h.ensureUserWorkspace(r.Context(), user); err != nil {
		writeError(w, http.StatusInternalServerError, "failed to provision workspace")
		return
	}

	h.completeLogin(w, r, user)
}

