type dbExecutor interface {
	Exec(ctx context.Context, sql string, arguments ...any) (pgconn.CommandTag, error)
	Query(ctx context.Context, sql string, args ...any) (pgx.Rows, error)
	QueryRow(ctx context.Context, sql string, args ...any) pgx.Row
}

type Handler struct {
	Queries      *db.Queries
	DB           dbExecutor
	TxStarter    txStarter
	Hub          *realtime.Hub
	Bus          *events.Bus
	TaskService  *service.TaskService
	EmailService *service.EmailService
	IdeaOS       *service.GitHubIdeaOSService
	GitHubOAuth  *service.GitHubOAuthService
	IdeaStore    *service.IdeaStore
	PingStore    *PingStore
	UpdateStore  *UpdateStore
	Storage      *storage.S3Storage
	CFSigner     *auth.CloudFrontSigner
}

func New(queries *db.Queries, txStarter txStarter, hub *realtime.Hub, bus *events.Bus, emailService *service.EmailService, s3 *storage.S3Storage, cfSigner *auth.CloudFrontSigner) *Handler {
	var executor dbExecutor
	if candidate, ok := txStarter.(dbExecutor); ok {
		executor = candidate
	}

	return &Handler{
		Queries:      queries,
		DB:           executor,
		TxStarter:    txStarter,
		Hub:          hub,
		Bus:          bus,
		TaskService:  service.NewTaskService(queries, hub, bus),
		EmailService: emailService,
		IdeaOS:       service.NewGitHubIdeaOSService(),
		GitHubOAuth:  service.NewGitHubOAuthService(),
		IdeaStore:    service.NewIdeaStore(),
		PingStore:    NewPingStore(),
		UpdateStore:  NewUpdateStore(),
		Storage:      s3,
		CFSigner:     cfSigner,
	}
}

func writeJSON(w http.ResponseWriter, status int, v any) {
