			Type:     "exit",
			ExitCode: exitCode,
			Error:    s.ExitError,
		}
	}
	s.mu.Unlock()

	return ch, buffer, exitEvent
}

func (s *adminSSHSession) snapshot() AdminSSHSessionResponse {
	s.mu.RLock()
	defer s.mu.RUnlock()

