func (s *adminSSHSession) resize(cols, rows int) error {
	if cols <= 0 || rows <= 0 {
		return errors.New("invalid terminal size")
	}

	s.mu.RLock()
	ptmx := s.ptmx
	status := s.Status
	s.mu.RUnlock()

	if status != "connected" || ptmx == nil {
