func (s *adminSSHSession) close(reason string) {
	now := time.Now().UTC()

	s.mu.Lock()
	if s.Status == "closed" || s.Status == "exited" {
		s.mu.Unlock()
		return
	}

	s.Status = "closed"
	s.ExitError = reason
	s.ExitedAt = &now
	s.UpdatedAt = now
	exitCode := -1
	s.ExitCode = &exitCode
	ptmx := s.ptmx
	cmd := s.cmd
	s.ptmx = nil
	s.mu.Unlock()

	if ptmx != nil {
		_ = ptmx.Close()
	}
	if cmd != nil && cmd.Process != nil {
		_ = cmd.Process.Kill()
	}

	s.publish(adminSSHStreamEvent{
		Type:     "exit",
		ExitCode: &exitCode,
		Error:    reason,
	})

	slog.Info("admin ssh session closed",
		"session_id", s.ID,
		"runtime_id", s.RuntimeID,
		"host", s.Host,
		"user_id", s.CreatedByUserID,
		"reason", reason,
	)
}

