			if err := conn.WriteJSON(event); err != nil {
				return
			}
			if event.Type == "exit" {
				return
			}
		}
	}()

	for {
		var msg adminSSHClientMessage
		if err := conn.ReadJSON(&msg); err != nil {
			break
		}

		switch msg.Type {

