+function readRuntimeSSHConfig(metadata: Record<string, unknown>): FrontendRuntimeSSHConfig {
+  if (metadata.ssh_enabled !== true) {
+    return { enabled: false, reason: "SSH access is not enabled for this runtime." };
+  }
