+    port = Math.trunc(portValue);
+  } else if (typeof portValue === "string" && portValue.trim()) {
+    const parsed = Number.parseInt(portValue.trim(), 10);
+    if (!Number.isNaN(parsed)) {
+      port = parsed;
+    }
+  }
+
+  if (!host || !user) {
+    return {
+      enabled: false,
+      reason: "SSH metadata is incomplete. Set ssh_host and ssh_user on the runtime.",
+    };
+  }
+
+  return {
+    enabled: true,
+    host,
+    port: port > 0 ? port : 22,
+    user,
+  };
