package handler

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

func loadTestRuntimeID(t *testing.T) string {
	t.Helper()

	var runtimeID string
	if err := testPool.QueryRow(t.Context(), `
		SELECT id
		FROM agent_runtime
		WHERE workspace_id = $1
		ORDER BY created_at ASC
		LIMIT 1
	`, testWorkspaceID).Scan(&runtimeID); err != nil {
		t.Fatalf("load runtime: %v", err)
	}

	return runtimeID
}

func TestGetMeMarksSuperAdmin(t *testing.T) {
	t.Setenv("SUPER_ADMIN_EMAIL", handlerTestEmail)

	req := newRequest(http.MethodGet, "/api/me", nil)
	w := httptest.NewRecorder()

	testHandler.GetMe(w, req)
	if w.Code != http.StatusOK {
		t.Fatalf("GetMe: expected 200, got %d: %s", w.Code, w.Body.String())
	}

	var resp UserResponse
	if err := json.NewDecoder(w.Body).Decode(&resp); err != nil {
		t.Fatalf("decode response: %v", err)
	}
	if !resp.IsSuperAdmin {
		t.Fatal("expected user to be marked as super admin")
	}
}

func TestCreateAdminSSHSessionRequiresSuperAdmin(t *testing.T) {
	t.Setenv("SUPER_ADMIN_EMAIL", "someone-else@multica.ai")

	runtimeID := loadTestRuntimeID(t)
	req := newRequest(http.MethodPost, "/api/admin/runtimes/"+runtimeID+"/ssh-sessions", nil)
	req = withURLParam(req, "runtimeId", runtimeID)
	w := httptest.NewRecorder()

	testHandler.CreateAdminSSHSession(w, req)
	if w.Code != http.StatusForbidden {
		t.Fatalf("CreateAdminSSHSession: expected 403, got %d: %s", w.Code, w.Body.String())
	}
}

func TestCreateAdminSSHSessionRejectsMissingSSHMetadata(t *testing.T) {
	t.Setenv("SUPER_ADMIN_EMAIL", handlerTestEmail)

	runtimeID := loadTestRuntimeID(t)
	req := newRequest(http.MethodPost, "/api/admin/runtimes/"+runtimeID+"/ssh-sessions", nil)
	req = withURLParam(req, "runtimeId", runtimeID)
	w := httptest.NewRecorder()

	testHandler.CreateAdminSSHSession(w, req)
	if w.Code != http.StatusBadRequest {
		t.Fatalf("CreateAdminSSHSession: expected 400, got %d: %s", w.Code, w.Body.String())
	}
	if !strings.Contains(w.Body.String(), "runtime SSH is not enabled") {
		t.Fatalf("expected missing SSH metadata error, got %s", w.Body.String())
	}
}

