          black: "#101828",
          red: "#ff7b7b",
          green: "#7be0ad",
          yellow: "#f2cf65",
          blue: "#8bd3ff",
          magenta: "#d4a5ff",
          cyan: "#86efe7",
          white: "#eef4ff",
          brightBlack: "#52627d",
          brightRed: "#ff9b9b",
          brightGreen: "#93efbb",
          brightYellow: "#ffe082",
          brightBlue: "#a7e3ff",
          brightMagenta: "#dfb6ff",
          brightCyan: "#9cf7ef",
          brightWhite: "#ffffff",
