"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import {
  AlertTriangle,
  Loader2,
  MonitorCog,
  Plug2,
  RefreshCw,
  Shield,
  SquareTerminal,
  Unplug,
} from "lucide-react";
import { api } from "@/shared/api";
import type { AdminSshSession, AgentRuntime } from "@/shared/types";
import { useAuthStore } from "@/features/auth";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

type TerminalConnectionState =
  | "idle"
  | "connecting"
  | "connected"
  | "disconnected"
  | "closed"
  | "exited";

type FrontendRuntimeSSHConfig =
  | {
      enabled: true;
      host: string;
      port: number;
      user: string;
      reason: "";
    }
  | {
      enabled: false;
      host: string | null;
      port: number | null;
      user: string | null;
      reason: string;
    };

type XTermModule = typeof import("xterm");
type FitAddonModule = typeof import("@xterm/addon-fit");
type TerminalInstance = InstanceType<XTermModule["Terminal"]>;
type FitAddonInstance = InstanceType<FitAddonModule["FitAddon"]>;

type AdminSshEvent = {
  type: string;
  data?: string;
  error?: string;
  exit_code?: number;
};

const DEFAULT_TMUX_SESSION_NAME = "multica-admin";

function readRuntimeSSHConfig(metadata: Record<string, unknown>): FrontendRuntimeSSHConfig {
  const enabled = metadata.ssh_enabled === true;
  const host = typeof metadata.ssh_host === "string"
    ? metadata.ssh_host.trim()
    : "";
  const user = typeof metadata.ssh_user === "string"
    ? metadata.ssh_user.trim()
    : "";

  let port = 22;
  if (typeof metadata.ssh_port === "number" && Number.isFinite(metadata.ssh_port)) {
    port = Math.trunc(metadata.ssh_port);
  } else if (typeof metadata.ssh_port === "string" && metadata.ssh_port.trim()) {
    const parsed = Number.parseInt(metadata.ssh_port.trim(), 10);
    if (!Number.isNaN(parsed) && parsed > 0) {
      port = parsed;
    }
  }

  if (!enabled) {
    return {
      enabled: false,
      host: host || null,
      port: host || user ? port : null,
      user: user || null,
      reason: "SSH access is not enabled for this runtime.",
    };
  }

  if (!host || !user) {
    return {
      enabled: false,
      host: host || null,
      port,
      user: user || null,
      reason: "SSH metadata is incomplete. Set ssh_host and ssh_user on the runtime.",
    };
  }

  return {
    enabled: true,
    host,
    port: port > 0 ? port : 22,
    user,
    reason: "",
  };
}

function resolveAdminSshWebSocketUrl(path: string, token: string): string {
  const base = process.env.NEXT_PUBLIC_API_URL
    ? new URL(process.env.NEXT_PUBLIC_API_URL, window.location.origin)
    : new URL(window.location.origin);
  const url = new URL(path, base);
  url.protocol = url.protocol === "https:" ? "wss:" : "ws:";
  url.searchParams.set("token", token);
  return url.toString();
}

function renderStatusLabel(state: TerminalConnectionState): string {
  switch (state) {
    case "connecting":
      return "Connecting";
    case "connected":
      return "Live";
    case "disconnected":
      return "Detached";
    case "closed":
      return "Closed";
    case "exited":
      return "Exited";
    default:
      return "Idle";
  }
}

function storageKeyForRuntime(runtimeId: string): string {
  return `multica_admin_ssh_session:${runtimeId}`;
}

export function RuntimeSshTerminal({ runtime }: { runtime: AgentRuntime }) {
  const user = useAuthStore((state) => state.user);
  const sshConfig = useMemo(
    () => readRuntimeSSHConfig(runtime.metadata),
    [runtime.metadata],
  );

  const terminalContainerRef = useRef<HTMLDivElement | null>(null);
  const terminalRef = useRef<TerminalInstance | null>(null);
  const fitAddonRef = useRef<FitAddonInstance | null>(null);
  const socketRef = useRef<WebSocket | null>(null);
  const resizeObserverRef = useRef<ResizeObserver | null>(null);
  const sessionRef = useRef<AdminSshSession | null>(null);

  const [terminalReady, setTerminalReady] = useState(false);
  const [restoring, setRestoring] = useState(false);
  const [session, setSession] = useState<AdminSshSession | null>(null);
  const [connectionState, setConnectionState] = useState<TerminalConnectionState>("idle");
  const [error, setError] = useState("");

  const storageKey = storageKeyForRuntime(runtime.id);

  useEffect(() => {
    sessionRef.current = session;
  }, [session]);

  useEffect(() => {
    if (!user?.is_super_admin || !terminalContainerRef.current) {
      return;
    }

    let disposed = false;
    let dataSubscription: { dispose: () => void } | null = null;
    let resizeSubscription: { dispose: () => void } | null = null;

    const setup = async () => {
      const [{ Terminal }, { FitAddon }] = await Promise.all([
        import("xterm"),
