        convertEol: true,
        fontFamily: "var(--font-mono)",
        fontSize: 13,
        lineHeight: 1.25,
        scrollback: 5000,
        theme: {
          background: "#08101d",
          foreground: "#d9e4ff",
          cursor: "#8bd3ff",
          cursorAccent: "#08101d",
          selectionBackground: "#25405f",
          black: "#101828",
          red: "#ff7b7b",
          green: "#7be0ad",
          yellow: "#f2cf65",
          blue: "#8bd3ff",
          magenta: "#d4a5ff",
          cyan: "#86efe7",
          white: "#eef4ff",
          brightBlack: "#52627d",
          brightRed: "#ff9b9b",
          brightGreen: "#93efbb",
          brightYellow: "#ffe082",
          brightBlue: "#a7e3ff",
          brightMagenta: "#dfb6ff",
          brightCyan: "#9cf7ef",
          brightWhite: "#ffffff",
        },
      });

      const fitAddon = new FitAddon();
      terminal.loadAddon(fitAddon);
      terminal.open(terminalContainerRef.current);
      fitAddon.fit();
      terminal.focus();
      terminal.writeln("\x1b[38;5;81mSSH control channel ready.\x1b[0m");

      dataSubscription = terminal.onData((data) => {
        if (socketRef.current?.readyState === WebSocket.OPEN) {
          socketRef.current.send(JSON.stringify({ type: "stdin", data }));
        }
      });

      resizeSubscription = terminal.onResize(({ cols, rows }) => {
        if (socketRef.current?.readyState === WebSocket.OPEN) {
          socketRef.current.send(JSON.stringify({ type: "resize", cols, rows }));
        }
      });

      if (typeof ResizeObserver !== "undefined") {
        const observer = new ResizeObserver(() => {
          fitAddon.fit();
          if (socketRef.current?.readyState === WebSocket.OPEN) {
            socketRef.current.send(JSON.stringify({
              type: "resize",
              cols: terminal.cols,
              rows: terminal.rows,
            }));
          }
        });
        observer.observe(terminalContainerRef.current);
        resizeObserverRef.current = observer;
      }

      terminalRef.current = terminal;
      fitAddonRef.current = fitAddon;
      setTerminalReady(true);
    };

    void setup();

    return () => {
      disposed = true;
      dataSubscription?.dispose();
      resizeSubscription?.dispose();
      resizeObserverRef.current?.disconnect();

