const fs = require("node:fs");
const { chromium } = require("/home/ubuntu/multica/node_modules/playwright");

const APP_URL = "http://127.0.0.1:13001";
const RUNTIME_NAME = "Codex (VM-0-3-ubuntu)";
const TOUCH_PATH = "/tmp/multica_ssh_e2e_ok";
const TOKEN_MARK = "MULTICA_SSH_E2E_OK";

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function waitForFile(path, timeoutMs = 10000) {
  const started = Date.now();
  while (Date.now() - started < timeoutMs) {
    if (fs.existsSync(path)) return true;
    await sleep(250);
  }
  return false;
}

(async () => {
  const email = process.env.SUPER_ADMIN_EMAIL;
  const password = process.env.SUPER_ADMIN_PASSWORD;
  if (!email || !password) {
    throw new Error("SUPER_ADMIN_EMAIL or SUPER_ADMIN_PASSWORD is missing");
  }

  fs.rmSync(TOUCH_PATH, { force: true });

  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 1100 } });
  page.on("console", (msg) => console.log(`[browser:${msg.type()}] ${msg.text()}`));

  try {
    await page.goto(`${APP_URL}/login`, { waitUntil: "networkidle" });
    await page.getByRole("tab", { name: /super admin/i }).click();
    await page.getByPlaceholder("admin@example.com").fill(email);
    await page.getByLabel("Password").fill(password);
    await Promise.all([
      page.waitForURL(/\/issues/),
      page.getByRole("button", { name: /sign in as admin/i }).click(),
    ]);

    await page.goto(`${APP_URL}/runtimes`, { waitUntil: "networkidle" });
    await page.getByText(RUNTIME_NAME).click();
    await page.getByText("SSH Terminal").waitFor({ state: "visible" });
    await page.screenshot({ path: "/tmp/multica_ssh_e2e_before.png", fullPage: true });

    const connectButton = page.getByRole("button", { name: /^connect$/i });
    await connectButton.waitFor({ state: "visible" });
    await connectButton.click();

    await page.getByText("Live").waitFor({ state: "visible", timeout: 20000 });
    await page.locator(".runtime-ssh-terminal").click({ position: { x: 320, y: 140 } });
    await page.keyboard.type(`touch ${TOUCH_PATH} && echo ${TOKEN_MARK}`);
    await page.keyboard.press("Enter");

    const touched = await waitForFile(TOUCH_PATH, 15000);
    if (!touched) {
      throw new Error("Remote shell command did not create the expected file");
    }

    await page.screenshot({ path: "/tmp/multica_ssh_e2e_after.png", fullPage: true });
    await page.getByRole("button", { name: /end session/i }).click();
    await page.getByText("Closed").waitFor({ state: "visible", timeout: 15000 });

    console.log(`E2E_OK runtime=${RUNTIME_NAME} file=${TOUCH_PATH}`);
  } finally {
    await browser.close();
  }
})().catch((error) => {
  console.error(error.stack || String(error));
  process.exit(1);
});

