const TOUCH_PATH = "/tmp/clawteam_prod_ssh_e2e_ok";

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function waitForFile(path, timeoutMs = 15000) {
  const started = Date.now();
  while (Date.now() - started < timeoutMs) {
    if (fs.existsSync(path)) return true;
    await sleep(250);
  }
  return false;
}

(async () => {
  const email = process.env.SUPER_ADMIN_EMAIL;
  const password = process.env.SUPER_ADMIN_PASSWORD;
  if (!email || !password) throw new Error("Missing super-admin credentials");

  fs.rmSync(TOUCH_PATH, { force: true });

  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 1100 } });
  page.on("console", (msg) => console.log(`[browser:${msg.type()}] ${msg.text()}`));

  try {
    await page.goto(`${APP_URL}/login`, { waitUntil: "networkidle" });
    await page.getByRole("tab", { name: /super admin/i }).click();
    await page.getByPlaceholder("admin@example.com").fill(email);
    await page.getByLabel("Password").fill(password);
    await Promise.all([
      page.waitForURL(/\/issues/),
      page.getByRole("button", { name: /sign in as admin/i }).click(),
    ]);

    await page.goto(`${APP_URL}/runtimes`, { waitUntil: "networkidle" });
    await page.getByText(RUNTIME_NAME).click();
    await page.getByText("SSH Terminal").waitFor({ state: "visible" });
    await page.getByRole("button", { name: /^connect$/i }).click();

    await page.locator(".runtime-ssh-terminal").getByText("Live").last().waitFor({
      state: "visible",
      timeout: 20000,
    });

    await page.locator(".runtime-ssh-terminal").click({ position: { x: 300, y: 140 } });
    await page.keyboard.type(`touch ${TOUCH_PATH} && echo CLAWTEAM_PROD_SSH_OK`);
    await page.keyboard.press("Enter");

    if (!(await waitForFile(TOUCH_PATH, 15000))) {
      throw new Error("SSH terminal command did not produce the expected file");
    }

    await page.getByRole("button", { name: /end session/i }).click();
    await page.locator(".runtime-ssh-terminal").getByText("Closed").last().waitFor({
      state: "visible",
      timeout: 15000,
    });

    console.log(`PROD_E2E_OK file=${TOUCH_PATH}`);
  } finally {
    await browser.close();
  }
})().catch((error) => {
  console.error(error.stack || String(error));
  process.exit(1);
});

